import{_ as s}from"./plugin-vue_export-helper-c27b6911.js";import{r as a,o as l,c as i,e as c,a as e,b as t,d as r,f as h}from"./app-40463a1e.js";const d={},p=e("h1",{id:"前言",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#前言","aria-hidden":"true"},"#"),t(" 前言")],-1),_=e("p",null,"在游戏引擎中，游戏对象的状态更新基本是由组件的生命周期来实现，比如在 update 中更新位置",-1),u=e("p",null,"但如果需要更新的游戏对象越多，各自处理自己的状态更新就会让游戏维护变的困难，比如将所有角色移动速度加快指定数值，需要在每个对象状态更新的位置修改，而 ECS 则可以统一、批量处理",-1),f=h('<h1 id="结构" tabindex="-1"><a class="header-anchor" href="#结构" aria-hidden="true">#</a> 结构</h1><ul><li><strong>E: 实体，游戏对象，由多个组件组成</strong></li><li><strong>C: 组件，单一职责，比如位移，跳跃</strong></li><li><strong>S：系统，负责指定类型的组件生命周期管理，比如移动系统（包含位移，跳跃）</strong></li></ul><h1 id="解决了什么问题" tabindex="-1"><a class="header-anchor" href="#解决了什么问题" aria-hidden="true">#</a> 解决了什么问题？</h1><ul><li><p>将分布式状态同步改为统一处理，减少游戏复杂度，增加可维护性</p></li><li><p>DOD/ECS 利用数据局部性可以让游戏性能提高</p></li></ul><blockquote><p>DOD：Data Oriented Design（面向数据的设计）</p></blockquote><h1 id="什么时候适合用-ecs" tabindex="-1"><a class="header-anchor" href="#什么时候适合用-ecs" aria-hidden="true">#</a> 什么时候适合用 ECS？</h1><p>游戏需要处理大量不同类型对象的状态更新时使用，如果是类似捕鱼类游戏，对象的更新基本只存在鱼和子弹上，那么就没太大必要使用 ECS，但如果类似英雄联盟，不同的角色几十个包含不同的技能，就比较适合使用 ECS</p><h1 id="如何在-ts-中使用-dod-ecs" tabindex="-1"><a class="header-anchor" href="#如何在-ts-中使用-dod-ecs" aria-hidden="true">#</a> 如何在 ts 中使用 DOD/ECS ？</h1><p>在 ts 中我们只能使用 TypesArray，也就是 <strong>ArrayBuffer、Uint8Array、Float64Array</strong>，这些类型来保证数据局部性，当然，使用这些类型数组我们 <strong>需要自己管理内存</strong> 的大小，以保证是连续的一块内存，这样才能保证缓存命中</p><ul><li>系统需要知道每个组件占用的内存（相同类型的组件使用的内存大小必须一致）</li><li>我们只能存储基础数据类型到内存</li></ul><p>参考：</p>',11),g={href:"https://github.com/thi-ng/umbrella/tree/develop/packages/ecs",target:"_blank",rel:"noopener noreferrer"},m={href:"https://javelin.hashnode.dev/ecs-in-js-a-closer-look-at-component-storage",target:"_blank",rel:"noopener noreferrer"},b=e("hr",null,null,-1),S=e("h3",null,"📣 觉得很赞？分享给你的朋友吧！",-1);function k(E,x){const o=a("ExternalLinkIcon"),n=a("Share");return l(),i("div",null,[p,_,u,c(" more "),f,e("ul",null,[e("li",null,[t("TS DOD/ECS 实现："),e("a",g,[t("https://github.com/thi-ng/umbrella/tree/develop/packages/ecs"),r(o)])]),e("li",null,[t("JS 中的 ECS——深入了解组件存储："),e("a",m,[t("https://javelin.hashnode.dev/ecs-in-js-a-closer-look-at-component-storage"),r(o)])])]),b,S,r(n,{services:"qq,qrcode",colorful:""})])}const D=s(d,[["render",k],["__file","25.html.vue"]]);export{D as default};
